import{_ as e,o as s,c as a,j as t,a as i,a2 as n}from"./chunks/framework.N6Nd-M9-.js";const b=JSON.parse('{"title":"🌟 榜样","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/01-榜样.md","filePath":"notes/企业文化/组长手册/01-榜样.md"}'),l={name:"notes/企业文化/组长手册/01-榜样.md"};function o(r,c,d,p,g,m){return s(),a("div",null,[...c[0]||(c[0]=[t("h1",{id:"🌟-榜样",tabindex:"-1"},[i("🌟 榜样 "),t("a",{class:"header-anchor",href:"#🌟-榜样","aria-label":'Permalink to "🌟 榜样"'},"​")],-1),t("blockquote",null,[t("p",null,"组长阶段是你踏入管理之路的开端，从此阶段起，你最重要的是做好的榜样，同时把你学到的经验传承给你的队员、激励你的队员。最直接有效的方法便是以身作则，用你的热忱、认真的态度、良好的品格来影响他人。")],-1),t("div",{class:"tc-grid tc-grid-sm",style:{gap:"12px"}},[t("div",{class:"tc-card tc-card-blue",style:{cursor:"pointer"},onclick:"document.getElementById('section-xiuye').scrollIntoView({behavior:'smooth'})"},[t("p",{class:"tc-blue tc-bold tc-center",style:{margin:"0","font-size":"16px"}},"🔧 修业"),t("p",{class:"tc-blue tc-sm tc-center",style:{margin:"8px 0 0 0",opacity:"0.8"}},"做好工作榜样")]),t("div",{class:"tc-card tc-card-green",style:{cursor:"pointer"},onclick:"document.getElementById('section-jinde').scrollIntoView({behavior:'smooth'})"},[t("p",{class:"tc-green tc-bold tc-center",style:{margin:"0","font-size":"16px"}},"🌱 进德"),t("p",{class:"tc-green tc-sm tc-center",style:{margin:"8px 0 0 0",opacity:"0.8"}},"做好生活榜样")]),t("div",{class:"tc-card tc-card-orange",style:{cursor:"pointer"},onclick:"document.getElementById('section-liuzhe').scrollIntoView({behavior:'smooth'})"},[t("p",{class:"tc-orange tc-bold tc-center",style:{margin:"0","font-size":"16px"}},"📋 六大准则"),t("p",{class:"tc-orange tc-sm tc-center",style:{margin:"8px 0 0 0",opacity:"0.8"}},"组长榜样标准")])],-1),n('<hr><div class="tc-container tc-container-blue"><p class="tc-blue tc-bold" style="font-size:18px;margin:0 0 15px 0;">💡 核心理念</p><div class="tc-sub" style="margin-bottom:15px;"><p class="tc-body" style="margin:0;font-size:15px;line-height:1.8;">同创主悦的价值观是正面积极的，作为同创人，人要正。榜样的力量无穷，生命可以影响生命，因此作为组长更要做好&quot;正&quot;的榜样。身正取决于心正，心正取决于内心的底气，底气来源于自身的&quot;功&quot;与&quot;德&quot;，无论是工作中还是生活中，都要严格要求自己，使队员信服。</p></div><div class="tc-quote tc-quote-red"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">作为榜样的&quot;影响&quot;要有成果，要靠&quot;修业、进德&quot;。</p></div></div><hr><h2 id="🔧-修业——做好工作榜样-扩大你的战果、提高你的成果" tabindex="-1">🔧 修业——做好工作榜样：扩大你的战果、提高你的成果 <a class="header-anchor" href="#🔧-修业——做好工作榜样-扩大你的战果、提高你的成果" aria-label="Permalink to &quot;🔧 修业——做好工作榜样：扩大你的战果、提高你的成果&quot;">​</a></h2><div id="section-xiuye" class="tc-container tc-container-blue"><div class="tc-sub"><p class="tc-body" style="margin:0;font-size:15px;line-height:1.8;">事实胜于雄辩，工作中自己要以切实行动影响队员，做出实际成果为队员树立工作标准。队员心中都有一杆工作标准的秤，秤的一边是你讲的道理，另一边是你的实际成果，只有当成果的重量等于甚至大于道理的重量之时，队员才会产生信服，你才开始具有工作上的榜样性。</p></div></div><hr><h2 id="🌱-进德——做好生活榜样-提升你的品格、认知、格局、高度" tabindex="-1">🌱 进德——做好生活榜样：提升你的品格、认知、格局、高度 <a class="header-anchor" href="#🌱-进德——做好生活榜样-提升你的品格、认知、格局、高度" aria-label="Permalink to &quot;🌱 进德——做好生活榜样：提升你的品格、认知、格局、高度&quot;">​</a></h2><div id="section-jinde" class="tc-container tc-container-green"><div class="tc-sub"><p class="tc-body" style="margin:0;font-size:15px;line-height:1.8;">生活与工作密不可分、互相影响。良好习惯成就美好人生，习惯形成于日常生活。作为组长，日常生活应做到自律，热衷于提升个人综合素质，成为团队的道德标杆。</p></div></div><hr><h2 id="📋-榜样的六大准则" tabindex="-1">📋 榜样的六大准则 <a class="header-anchor" href="#📋-榜样的六大准则" aria-label="Permalink to &quot;📋 榜样的六大准则&quot;">​</a></h2><div id="section-liuzhe" class="tc-grid tc-grid-auto" style="gap:15px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue" style="margin:0 0 12px 0;">1. 成功品格</p><div class="tc-flex tc-flex-wrap" style="gap:8px;"><span class="tc-tag tc-tag-blue tc-body">尊重</span><span class="tc-tag tc-tag-blue tc-body">利他</span><span class="tc-tag tc-tag-blue tc-body">共赢</span></div></div><div class="tc-card tc-card-green"><p class="tc-title tc-green" style="margin:0 0 12px 0;">2. 良好的态度</p><div class="tc-flex tc-flex-wrap" style="gap:8px;"><span class="tc-tag tc-tag-green tc-body">谦卑</span><span class="tc-tag tc-tag-green tc-body">顺服</span><span class="tc-tag tc-tag-green tc-body">好学</span><span class="tc-tag tc-tag-green tc-body">愿意改变</span></div></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange" style="margin:0 0 12px 0;">3. 责任感</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-orange tc-body">用持续的钟声营造公司氛围。</span><span class="tc-item tc-item-orange tc-body">培训好拍档。</span><span class="tc-item tc-item-orange tc-body">很好地协调解决队员的问题。</span><span class="tc-item tc-item-orange tc-body">能够努力完成早晚黄金时间所订的目标。</span><span class="tc-item tc-item-orange tc-body">很好地完成公司所安排的特别任务。</span><span class="tc-item tc-item-orange tc-body">爱护好公司的货物。</span><span class="tc-item tc-item-orange tc-body">困难时刻仍然具备对生意负责任的态度。</span><span class="tc-item tc-item-orange tc-body">新产品上市要主动带动、了解。</span></div></div><div class="tc-card tc-card-red"><p class="tc-title tc-red" style="margin:0 0 12px 0;">4. 学习与教育的能力</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-red tc-body">用未来身份做现在事。</span><span class="tc-item tc-item-red tc-body">作为一个老师，懂得有效地教育队员的五步、八点、平均法。</span><span class="tc-item tc-item-red tc-body">为完善制度提供建议。</span><span class="tc-item tc-item-red tc-body">了解并推广企业文化及未来的发展方向等。</span></div></div><div class="tc-card tc-card-blue"><p class="tc-title tc-blue" style="margin:0 0 12px 0;">5. 稳定的赚钱能力</p><div class="tc-sub"><p class="tc-body" style="margin:0;font-size:14px;">组长=完成任务：水准不低于打钟的一半。</p></div></div><div class="tc-card tc-card-green"><p class="tc-title tc-green" style="margin:0 0 12px 0;">6. 独立作业的能力</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-green tc-body">有能力自我鼓励。</span><span class="tc-item tc-item-green tc-body">懂得安排地区作业。</span><span class="tc-item tc-item-green tc-body">新产品的推广。</span><span class="tc-item tc-item-green tc-body">主动要求自己好上加好、高标准。</span></div></div></div>',11)])])}const u=e(l,[["render",o]]);export{b as __pageData,u as default};
